mapper.select:
SELECT EXISTS (
    SELECT 1 FROM franchise WHERE manager_id = #{managerId}
)

SELECT EXISTS (
    SELECT 1 FROM franchise WHERE department_id = #{departmentId}
)

SELECT EXISTS(
    SELECT 1 FROM franchise WHERE owner_id = #{userId}
)

SELECT s.id, f.id AS franchise_id, f.name AS franchise_name, s.year, s.month, s.order_amount, s.created_at, s.updated_at, s.is_deleted, s.deleted_reason, s.deleted_at FROM franchise_order_amount_stat s JOIN franchise f ON s.franchise_id = f.id WHERE f.manager_id = #{managerId}
AND s.year = #{year}
AND s.month = #{month}

SELECT s.id, f.id AS franchise_id, f.name AS franchise_name, s.year, s.month, s.order_amount, s.created_at, s.updated_at, s.is_deleted, s.deleted_reason, s.deleted_at FROM franchise_order_amount_stat s JOIN franchise f ON s.franchise_id = f.id WHERE f.department_id = #{departmentId}
AND s.`year` = #{year}
AND s.`month` = #{month}

SELECT s.id, f.id AS franchise_id, f.name AS franchise_name, s.year, s.month, s.order_amount, s.created_at, s.updated_at, s.is_deleted, s.deleted_reason, s.deleted_at FROM franchise_order_amount_stat s JOIN franchise f ON s.franchise_id = f.id WHERE f.owner_id = #{userId}
AND s.year = #{year}
AND s.month = #{month}
